<div class="page-header"><div><h2 class="page-title">Modifier la relation post / categorie</h2><p class="page-meta">Mettez a jour le lien entre article et categorie.</p></div></div><form action="/admin/post-categories/update"class="card form-card"method="post"><input name="old_post_id"type="hidden"value="<?=(int)$relation['post_id']?>"> <input name="old_category_id"type="hidden"value="<?=(int)$relation['category_id']?>"><div class="form-field"><label for="post_id">Article</label> <select class="form-select"id="post_id"name="post_id"required><?php foreach($posts as $post): ?><option value="<?=(int)$post['id']?>"<?=(int)$post['id']===(int)$relation['post_id']?'selected':''?>>#<?=(int)$post['id']?>-<?=htmlspecialchars($post['title'])?></option><?php endforeach; ?></select></div><div class="form-field"><label for="category_id">Categorie</label> <select class="form-select"id="category_id"name="category_id"required><?php foreach($categories as $category): ?><option value="<?=(int)$category['id']?>"<?=(int)$category['id']===(int)$relation['category_id']?'selected':''?>>#<?=(int)$category['id']?>-<?=htmlspecialchars($category['name'])?></option><?php endforeach; ?></select></div><button class="btn btn-primary"type="submit">Mettre a jour</button> <a class="btn btn-ghost"href="/admin/post-categories">Annuler</a></form>